import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Implementing proper security measures
        int maxLength = 20; // Maximum allowed length for the name
        char[] buffer = new char[Math.min(name.length(), maxLength)];

        // Copy characters from name to buffer
        name.getChars(0, Math.min(name.length(), maxLength), buffer, 0);

        System.out.println("Hello, " + new String(buffer));
    }
}

